 1	import React, { ChangeEvent, FC } from 'react';
 2	import { Controller, useFormContext } from 'react-hook-form';
 3	
 4	import FormGroupHelperText from '@kubevirt-utils/components/FormGroupHelperText/FormGroupHelperText';
 5	import { DataUpload } from '@kubevirt-utils/hooks/useCDIUpload/useCDIUpload';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import {
 8	  DropEvent,
 9	  FileUpload,
10	  FormGroup,
11	  Stack,
12	  StackItem,
13	  ValidatedOptions,
14	} from '@patternfly/react-core';
15	
16	import { UPLOAD_SOURCE_NAME } from '../../constants';
17	
18	import { SelectSourceUploadPVCProgress } from './SelectSourceUploadPVCProgress';
19	
20	type UploadSourceProps = {
21	  onFileSelected: (file: File | string) => void;
22	  relevantUpload: DataUpload;
23	  testId: string;
24	};
25	
26	const UploadSource: FC<UploadSourceProps> = ({ onFileSelected, relevantUpload, testId }) => {
27	  const { t } = useKubevirtTranslation();
28	
29	  const {
30	    control,
31	    formState: { errors },
32	  } = useFormContext();
33	
34	  const validated = errors?.[`${testId}-uploadFile`]
35	    ? ValidatedOptions.error
36	    : ValidatedOptions.default;
37	  return (
38	    <FormGroup
39	      className="disk-source-form-group"
40	      fieldId={`${testId}-${UPLOAD_SOURCE_NAME}`}
41	      isRequired
42	      label={t('Upload data')}
43	    >
44	      <Stack hasGutter>
45	        <StackItem>
46	          <Controller
47	            render={({ field: { onChange, value: fileValue }, fieldState: { error } }) => (
48	              <FileUpload
49	                onDataChange={(event: DropEvent, data: string) => {
50	                  onFileSelected(data);
51	                  onChange({ value: data });
52	                }}
53	                onFileInputChange={(event: DropEvent, file: File) => {
54	                  onFileSelected(file);
55	                  onChange({ filename: file.name });
56	                }}
57	                onTextChange={(event: ChangeEvent, text: string) => {
58	                  onFileSelected(text);
59	                  onChange({ value: text });
60	                }}
61	                data-test-id="disk-source-upload-pvc-file"
62	                filename={fileValue?.filename}
63	                filenamePlaceholder={t('Drag and drop an image or upload one')}
64	                id={`${testId}-uploadFile`}
65	                name={`${testId}-uploadFile`}
66	                onClearClick={() => onChange(undefined)}
67	                validated={error ? ValidatedOptions.error : ValidatedOptions.default}
68	                value={fileValue?.value}
69	              />
70	            )}
71	            control={control}
72	            name={`${testId}-uploadFile`}
73	            rules={{ required: true }}
74	            shouldUnregister
75	          />
76	          <FormGroupHelperText validated={validated}>
77	            {validated === ValidatedOptions.error && t('This field is required')}
78	          </FormGroupHelperText>
79	        </StackItem>
80	        <StackItem>
81	          {relevantUpload && <SelectSourceUploadPVCProgress upload={relevantUpload} />}
82	        </StackItem>
83	      </Stack>
84	    </FormGroup>
85	  );
86	};
87	
88	export default UploadSource;

